"use client";

import { useState, useEffect } from "react";
import { fetchDashboard } from "@/lib/api";
import { getWatchlist } from "@/lib/watchlist";
import type { DashboardResponse, WatchlistItem } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import Link from "next/link";
import { TrendingUp, TrendingDown, Minus, Star } from "lucide-react";

export default function DashboardPage() {
  const [data, setData] = useState<DashboardResponse | null>(null);
  const [watchlist, setWatchlist] = useState<WatchlistItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    fetchDashboard()
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);
  useEffect(() => {
    getWatchlist().then(setWatchlist);
  }, []);

  if (loading) return <LoadingSpinner text="대시보드 로딩 중..." />;
  if (error) return <ErrorMessage message={error} onRetry={load} />;
  if (!data) return null;

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">대시보드</h1>

      {/* 시장 지수 */}
      <div className="grid grid-cols-2 gap-4">
        {Object.entries(data.market_summary).map(([key, idx]) => (
          <div key={key} className="bg-white/5 border border-white/10 rounded-xl p-4">
            <p className="text-sm text-gray-400 uppercase">{key}</p>
            <p className="text-2xl font-bold">{idx.value.toLocaleString()}</p>
            <p className={`text-sm font-medium ${idx.change_rate > 0 ? "text-green-400" : idx.change_rate < 0 ? "text-red-400" : "text-gray-400"}`}>
              {idx.change_rate > 0 ? "+" : ""}{idx.change_rate}%
            </p>
          </div>
        ))}
      </div>

      {/* 내 관심 종목 */}
      <section>
        <h2 className="text-lg font-bold mb-3 flex items-center gap-2">
          <Star className="w-5 h-5 text-amber-400" />
          내 관심 종목
        </h2>
        {watchlist.length === 0 ? (
          <div className="bg-white/5 border border-white/10 rounded-xl p-6 text-center text-gray-400 text-sm">
            <p>관심 종목이 없어요.</p>
            <p className="mt-1">종목 검색 → 상세 페이지에서 별 아이콘을 눌러 추가해 보세요.</p>
            <Link href="/stock" className="inline-block mt-3 text-skyblue hover:underline">종목 검색</Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {watchlist.map((w) => (
              <Link key={w.id} href={`/stock/${w.stock_code}`} className="bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors flex items-center justify-between">
                <div>
                  <p className="font-medium">{w.stock_name}</p>
                  <p className="text-xs text-gray-400">{w.stock_code}</p>
                </div>
              </Link>
            ))}
          </div>
        )}
      </section>

      {/* 인기 종목 */}
      <section>
        <h2 className="text-lg font-bold mb-3">인기 종목</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {data.trending_stocks.map((s) => (
            <Link key={s.code} href={`/stock/${s.code}`} className="bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors flex items-center justify-between">
              <div>
                <p className="font-medium">{s.name}</p>
                <p className="text-xs text-gray-400">{s.code}</p>
              </div>
              <div className={`flex items-center gap-1 font-bold ${s.change_rate > 0 ? "text-green-400" : s.change_rate < 0 ? "text-red-400" : "text-gray-400"}`}>
                {s.change_rate > 0 ? <TrendingUp className="w-4 h-4" /> : s.change_rate < 0 ? <TrendingDown className="w-4 h-4" /> : <Minus className="w-4 h-4" />}
                {s.change_rate > 0 ? "+" : ""}{s.change_rate}%
              </div>
            </Link>
          ))}
        </div>
      </section>

      {/* 최신 뉴스 */}
      <section>
        <div className="flex justify-between items-center mb-3">
          <div>
            <h2 className="text-lg font-bold">최신 뉴스</h2>
            <p className="text-xs text-gray-400">쉽게 요약해 드려요</p>
          </div>
          <Link href="/issues" className="text-sm text-skyblue hover:underline">전체 보기</Link>
        </div>
        <div className="space-y-3">
          {data.top_news.map((n) => (
            <Link key={n.id} href={`/issues/${n.id}`} className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors">
              <p className="font-medium">{n.title}</p>
              <p className="text-xs text-gray-400 mt-1">{n.source} &middot; {new Date(n.published_at).toLocaleDateString("ko-KR")}</p>
            </Link>
          ))}
        </div>
      </section>

      {/* 주요 정책 */}
      <section>
        <div className="flex justify-between items-center mb-3">
          <div>
            <h2 className="text-lg font-bold">주요 정책</h2>
            <p className="text-xs text-gray-400">쉽게 풀어서 설명해 드려요</p>
          </div>
          <Link href="/policy" className="text-sm text-skyblue hover:underline">전체 보기</Link>
        </div>
        <div className="space-y-3">
          {data.hot_policies.map((p) => (
            <Link key={p.id} href={`/policy/${p.id}`} className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors">
              <p className="font-medium">{p.title}</p>
              <p className="text-xs text-gray-400 mt-1">{p.department}</p>
            </Link>
          ))}
        </div>
      </section>
    </div>
  );
}
